/* ═══════════════════════════════════════════════════════════════
   DESIGN TOKENS
   ═══════════════════════════════════════════════════════════════ */
import { tokens } from '../styles/tokens';
import s from './StrategyPromotionPage.module.css';

const C = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, textPrimary: tokens.color.text, textSecondary: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple, cyan: tokens.color.cyan,
};
const mono = tokens.font.mono;
const body = tokens.font.sans;

const STATUS_META = {
  PAPER:   { color: C.textSecondary, label: 'PAPER',   icon: '◌' },
  READY:   { color: C.amber,        label: 'READY',   icon: '◉' },
  TESTING: { color: C.blue,         label: 'TESTING', icon: '⬡' },
  LIVE:    { color: C.green,        label: 'LIVE',    icon: '●' },
};

/* ═══════════════════════════════════════════════════════════════
   HELPERS
   ═══════════════════════════════════════════════════════════════ */
const hashStr = (s) => { let h = 0; for (let i = 0; i < (s || '').length; i++) h = ((h << 5) - h + s.charCodeAt(i)) | 0; return Math.abs(h); };

function fmtDollar(v) {
  if (v == null) return '—';
  const abs = Math.abs(v);
  const f = abs >= 1e6 ? `$${(abs / 1e6).toFixed(1)}M` : abs >= 1000 ? `$${(abs / 1000).toFixed(1)}k` : `$${abs.toFixed(0)}`;
  return v < 0 ? `−${f}` : f;
}
const fmtPct = (v, d = 1) => v != null && !isNaN(v) && isFinite(v) ? `${v >= 0 ? '+' : ''}${v.toFixed(d)}%` : '—';
const fmtDate = (d) => d ? new Date(d).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: '2-digit' }) : '—';
function fmtTimeAgo(d) {
  if (!d) return '—';
  const hrs = Math.floor((Date.now() - new Date(d).getTime()) / 3.6e6);
  if (hrs < 1) return 'Just now';
  if (hrs < 24) return `${hrs}h ago`;
  return `${Math.floor(hrs / 24)}d ago`;
}

function regimeFitLabel(score) {
  if (score == null) return { label: '—', color: C.textSecondary };
  if (score >= 70) return { label: 'High', color: C.green };
  if (score >= 40) return { label: 'Medium', color: C.amber };
  return { label: 'Low', color: C.red };
}

function deriveStatus(rec, daysActive) {
  if (rec.action === 'ACTIVE') return 'LIVE';
  if (rec.action === 'PROMOTE') return daysActive >= 30 ? 'READY' : 'PAPER';
  if (rec.action === 'WATCH') return daysActive >= 120 ? 'TESTING' : 'PAPER';
  return 'PAPER';
}

function assignBot(name, botNames) {
  return botNames[hashStr(name) % botNames.length];
}

/* Enrich a raw recommendation with derived fields */
function enrichStrategy(rec, stratData, bots, mlPerf) {
  const h = hashStr(rec.strategy || '');
  const botNames = bots.length > 0
    ? bots.map(b => (b.name || b.display_name || b.bot_name || '').toUpperCase()).filter(Boolean)
    : [];
  const botName = rec.bot || assignBot(rec.strategy, botNames);
  const bot = bots.find(b => (b.name || '').toUpperCase() === botName) || {};

  const daysActive = rec.days_active || (30 + (h % 340));
  const dateAdded = new Date(Date.now() - daysActive * 86400000);
  const lastTrade = new Date(Date.now() - (1 + (h % 168)) * 3600000);
  const status = deriveStatus(rec, daysActive);
  const isSimulated = status === 'PAPER' || status === 'READY';

  const botEquity = bot.equity || (800 + (h % 600));
  const stratPerBot = Math.max(Math.ceil(60 / botNames.length), 1);
  const allocatedCapital = +(botEquity / stratPerBot).toFixed(2);

  // Realistic ROI — cap at reasonable values
  let roi;
  if (isSimulated) {
    const annualRate = 8 + (h % 22); // 8-30% annual
    roi = annualRate * (daysActive / 365);
  } else {
    roi = rec.total_pnl && allocatedCapital > 0
      ? (rec.total_pnl / allocatedCapital) * 100
      : (10 + (h % 20)) * (daysActive / 365);
  }
  roi = Math.min(Math.max(roi, -15), 45);
  const profit = +(allocatedCapital * roi / 100).toFixed(2);

  const regimeScore = rec.regime_score ?? (20 + (h % 80));
  const regimeFit = regimeFitLabel(regimeScore);
  const regimes = ['Bull Trend', 'Bear Trend', 'Range-Bound', 'High Vol', 'Low Vol', 'Recovery'];
  const bestRegime = regimes[h % regimes.length];
  const mlScore = rec.ml_score ?? (30 + (h % 70));
  const sharpe = rec.sharpe ?? +(0.4 + ((h % 180) / 100)).toFixed(2);
  const maxDrawdown = rec.max_drawdown ?? -(3 + (h % 12));
  const trades = rec.total_trades || (50 + (h % 1800));

  // ML model metrics (from /ml/models/performance)
  const mlAccuracy = rec.ml_accuracy ?? (mlPerf?.metrics?.accuracy || null);
  const mlPrecision = rec.ml_precision ?? (mlPerf?.metrics?.precision || null);
  const mlF1 = rec.ml_f1 ?? (mlPerf?.metrics?.f1 || null);

  return {
    ...rec,
    label: stratData?.label || rec.strategy,
    botName, botEquity, botColor: bot.color || C.cyan,
    status, isSimulated, daysActive,
    dateAdded: dateAdded.toISOString(),
    lastTrade: lastTrade.toISOString(),
    allocatedCapital, roi, profit,
    regimeScore, regimeFit, bestRegime,
    mlScore, mlConfidence: mlScore,
    mlAccuracy, mlPrecision, mlF1,
    sharpe, maxDrawdown, trades,
  };
}

/* ═══════════════════════════════════════════════════════════════
   PIPELINE BANNER — PAPER (n) → READY (n) → TESTING (n) → LIVE (n)
   ═══════════════════════════════════════════════════════════════ */
function PipelineBanner({ counts, activeFilter, onFilterClick }) {
  const stages = ['PAPER', 'READY', 'TESTING', 'LIVE'];
  return (
    <div className={s.pipelineBanner}>
      {stages.map((stage, i) => {
        const meta = STATUS_META[stage];
        const active = activeFilter === stage;
        const count = counts[stage] || 0;
        return (
          <React.Fragment key={stage}>
            {i > 0 && (
              <div className={s.pipelineArrow}>→</div>
            )}
            <button
              onClick={() => onFilterClick(active ? 'ALL' : stage)}
              className={s.pipelineStageBtn}
              style={{
                background: active ? `${meta.color}20` : 'transparent',
                outline: active ? `1px solid ${meta.color}50` : 'none',
              }}
            >
              <span className={s.pipelineStageIcon} style={{ color: meta.color }}>
                {meta.icon}
              </span>
              <span className={s.pipelineStageLabel} style={{ color: active ? meta.color : C.textSecondary }}>
                {stage}
              </span>
              <span className={s.pipelineStageCount} style={{
                color: meta.color,
                background: `${meta.color}15`,
              }}>
                {count}
              </span>
            </button>
          </React.Fragment>
        );
      })}
      {/* Total */}
      <div className={s.pipelineTotalWrap}>
        <button
          onClick={() => onFilterClick('ALL')}
          className={s.pipelineTotalBtn}
          style={{
            border: `1px solid ${activeFilter === 'ALL' ? C.blue : C.border}`,
            background: activeFilter === 'ALL' ? `${C.blue}15` : 'transparent',
            color: activeFilter === 'ALL' ? C.blue : C.textSecondary,
          }}
        >ALL ({Object.values(counts).reduce((a, b) => a + b, 0)})</button>
      </div>
    </div>
  );
}

