/* ═══════════════════════════════════════════════════════════════
   SCORE BAR
   ═══════════════════════════════════════════════════════════════ */
function ScoreBar({ value, max = 100, color, label }) {
  const pct = Math.min(((value || 0) / max) * 100, 100);
  return (
    <div className={s.scoreBarWrap}>
      <div className={s.scoreBarHeader}>
        <span className={s.scoreBarLabel}>{label}</span>
        <span className={s.scoreBarValue} style={{ color }}>{(value || 0).toFixed(1)}</span>
      </div>
      <div className={s.scoreBarTrack}>
        <div className={s.scoreBarFill} style={{ width: `${pct}%`, background: color }} />
      </div>
    </div>
  );
}

