/* ═══════════════════════════════════════════════════════════════
   RISK CHECK ITEM (for approval modal)
   ═══════════════════════════════════════════════════════════════ */
function RiskCheck({ pass, warn, label }) {
  const icon = pass ? '✓' : warn ? '⚠' : '✗';
  const color = pass ? C.green : warn ? C.amber : C.red;
  return (
    <div className={s.riskCheck}>
      <span className={s.riskCheckIcon} style={{ color }}>{icon}</span>
      <span className={s.riskCheckLabel}>{label}</span>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════
   APPROVAL MODAL
   ═══════════════════════════════════════════════════════════════ */
function ApprovalModal({ strategy, onClose, onPromote, mlPerf }) {
  const [allocationPct, setAllocationPct] = useState(10);
  const [submitting, setSubmitting] = useState(false);
  const [reason, setReason] = useState('');

  const st = strategy;
  const allocAmt = +((st.botEquity ?? 0) * allocationPct / 100).toFixed(2);
  const maxPosSize = +(allocAmt * 0.05).toFixed(2);
  const isFromTesting = st.status === 'TESTING';
  const targetStatus = isFromTesting ? 'LIVE' : 'TESTING';

  // Risk checks
  const checks = [
    { pass: st.daysActive >= 30, warn: false, label: `Minimum 30 days completed (${st.daysActive} days)` },
    { pass: st.sharpe >= 1.0, warn: st.sharpe >= 0.7 && st.sharpe < 1.0, label: `Sharpe ratio > 1.0 (${st.sharpe?.toFixed(2)})` },
    { pass: (st.win_rate || 0) >= 50, warn: (st.win_rate || 0) >= 45, label: `Win rate > 50% (${(st.win_rate || 0).toFixed(1)}%)` },
    { pass: Math.abs(st.maxDrawdown) < 10, warn: Math.abs(st.maxDrawdown) < 15, label: `Drawdown acceptable <15% (${st.maxDrawdown?.toFixed(1)}%)` },
    { pass: st.trades >= 100, warn: st.trades >= 50, label: `Sufficient trades (${st.trades?.toLocaleString()})` },
  ];
  const passCount = checks.filter(c => c.pass).length;
  const allPassing = passCount >= 4;

  const handlePromote = async () => {
    setSubmitting(true);
    const res = await apiPost(`/strategies/${encodeURIComponent(st.strategy)}/promote`, {
      reason: reason || `Promoted to ${targetStatus} — ${passCount}/${checks.length} risk checks passed`,
      requested_by: 'admin',
      allocation_pct: allocationPct,
    });
    setSubmitting(false);
    if (res && !res.error && !res.detail) {
      onPromote?.();
    }
  };

  // ML model features
  const features = mlPerf?.feature_importance || [];

  return (
    <div className={s.modalOverlay} onClick={onClose}>
      <div className={s.modalPanel} onClick={e => e.stopPropagation()}>

        {/* Header */}
        <div className={s.modalHeader}>
          <div className={s.modalTitle}>
            Promote Strategy to {targetStatus === 'LIVE' ? 'Live Trading' : 'Testing'}
          </div>
          <button onClick={onClose} className={s.modalCloseBtn}>&times;</button>
        </div>

        {/* Strategy + Bot context */}
        <div className={s.modalStratContext}>
          <span className={s.modalStratName}>{st.label}</span>
          <span className={s.modalBotLabel} style={{ color: st.botColor }}>
            {st.botName} ({fmtDollar(st.botEquity)} equity)
          </span>
          {st.isSimulated && (
            <span className={s.simBadge} style={{ background: `${C.amber}20`, color: C.amber }}>SIMULATED</span>
          )}
        </div>
        <div className={s.modalStratMeta}>
          {st.direction?.toUpperCase()} · {st.daysActive} days active · {st.trades?.toLocaleString()} trades
        </div>

        {/* Performance */}
        <div className={s.sectionLabel}>{st.isSimulated ? 'PAPER' : 'LIVE'} PERFORMANCE ({st.daysActive} days)</div>
        <div className={s.perfGrid}>
          <div className={s.perfGridItem}>
            Sharpe: <span className={s.perfGridValue} style={{ color: st.sharpe >= 1 ? C.green : C.amber }}>{st.sharpe?.toFixed(2)}</span>
          </div>
          <div className={s.perfGridItem}>
            Win Rate: <span className={s.perfGridValue} style={{ color: (st.win_rate || 0) >= 50 ? C.green : C.red }}>{(st.win_rate || 0).toFixed(1)}%</span>
          </div>
          <div className={s.perfGridItem}>
            ROI: <span className={s.perfGridValue} style={{ color: st.roi >= 0 ? C.green : C.red }}>{fmtPct(st.roi)}</span>
          </div>
          <div className={s.perfGridItem}>
            Max Drawdown: <span className={s.perfGridValue} style={{ color: C.red }}>{st.maxDrawdown != null ? `${st.maxDrawdown.toFixed(1)}%` : '--'}</span>
          </div>
          <div className={s.perfGridItem}>
            Total Trades: <span className={s.perfGridValue} style={{ color: C.textPrimary }}>{st.trades?.toLocaleString()}</span>
          </div>
          <div className={s.perfGridItem}>
            Profit Factor: <span className={s.perfGridValue} style={{ color: st.profit_factor != null && st.profit_factor >= 1.5 ? C.green : st.profit_factor != null ? C.amber : C.textSecondary }}>{st.profit_factor != null ? Number(st.profit_factor).toFixed(2) : '--'}{st.low_sample && ' ⚠'}</span>
          </div>
        </div>

        {/* Capital context */}
        <div className={s.capitalContext}>
          {fmtDollar(st.allocatedCapital)} → {fmtDollar(st.allocatedCapital + st.profit)}{' '}
          <span className={s.capitalContextRoi} style={{ color: st.roi >= 0 ? C.green : C.red }}>({fmtPct(st.roi)} in {st.daysActive}d)</span>
        </div>

        {/* ML Model Assessment */}
        <div className={s.sectionLabel}>AURA ALPHA ML ASSESSMENT</div>
        <div className={s.mlAssessment}>
          <div className={s.mlScoresRow}>
            <ScoreBar value={st.composite_score} color={C.blue} label="Composite" />
            <ScoreBar value={st.mlScore} color={C.purple} label="ML Confidence" />
            <ScoreBar value={st.regimeScore} color={C.amber} label="Regime Fit" />
          </div>
          <div className={s.mlRegimeLine}>
            Best regime: <span className={s.mlRegimeValue}>{st.bestRegime}</span>
            {st.regime_aligned && <span className={s.mlRegimeAligned}>● REGIME ALIGNED</span>}
          </div>
          {(st.mlAccuracy || st.mlPrecision || st.mlF1) && (
            <div className={s.mlMetricsRow}>
              {st.mlAccuracy && <span>Accuracy: <span className={s.mlMetricHighlight}>{(st.mlAccuracy * 100).toFixed(1)}%</span></span>}
              {st.mlPrecision && <span>Precision: <span className={s.mlMetricHighlight}>{(st.mlPrecision * 100).toFixed(1)}%</span></span>}
              {st.mlF1 && <span>F1: <span className={s.mlMetricHighlight}>{st.mlF1.toFixed(3)}</span></span>}
            </div>
          )}
          {features.length > 0 && (
            <div className={s.mlFeaturesWrap}>
              <div className={s.mlFeaturesTitle}>Top ML Features</div>
              {features.slice(0, 4).map(f => (
                <div key={f.feature || f.name} className={s.mlFeatureRow}>
                  <div className={s.mlFeatureBarTrack}>
                    <div className={s.mlFeatureBarFill} style={{ width: `${(f.importance || f.weight || 0) * 100}%` }} />
                  </div>
                  <span className={s.mlFeatureName}>{f.feature || f.name}</span>
                  <span className={s.mlFeatureWeight}>{((f.importance || f.weight || 0) * 100).toFixed(0)}%</span>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Risk Assessment */}
        <div className={s.sectionLabel}>RISK ASSESSMENT</div>
        <div className={s.riskAssessment}>
          {checks.map((c, i) => (
            <RiskCheck key={i} pass={c.pass} warn={c.warn} label={c.label} />
          ))}
          <div className={s.riskSummary} style={{ color: allPassing ? C.green : C.amber }}>
            {passCount}/{checks.length} checks passed {allPassing ? '— Ready for promotion' : '— Review recommended'}
          </div>
        </div>

        {/* Allocation */}
        <div className={s.sectionLabel}>ALLOCATION</div>
        <div className={s.allocationBox}>
          <div className={s.allocationSliderRow}>
            <span className={s.allocationSliderLabel}>Starting:</span>
            <input
              type="range" min={5} max={50} step={5} value={allocationPct}
              onChange={e => setAllocationPct(+e.target.value)}
              className={s.allocationSlider}
            />
            <span className={s.allocationPctValue}>{allocationPct}%</span>
          </div>
          <div className={s.allocationEquity}>
            {allocationPct}% of bot equity = <span className={s.allocationEquityValue}>{fmtDollar(allocAmt)}</span>
          </div>
          <div className={s.allocationMaxPos}>
            Max position size: {fmtDollar(maxPosSize)}/trade
          </div>
        </div>

        {/* Reason */}
        <div className={s.sectionLabel}>REASON (optional)</div>
        <textarea
          value={reason}
          onChange={e => setReason(e.target.value)}
          placeholder="Enter promotion rationale..."
          rows={2}
          className={s.reasonInput}
        />

        {/* Actions */}
        <div className={s.modalActions}>
          <button onClick={onClose} className={s.cancelBtn}>Cancel</button>
          <button onClick={handlePromote} disabled={submitting} className={s.promoteBtn} style={{
            background: targetStatus === 'LIVE' ? C.green : C.blue,
          }}>
            {submitting ? 'Submitting...' : `Promote to ${targetStatus} →`}
          </button>
        </div>
      </div>
    </div>
  );
}

